{
  "dbName": "{dbName}",
  "db": {
    "server": "{server}",
    "database": "{dbName}",
    "user": "{user}",
    "password": "<REDACTED>"
  },
  "query": "WITH skus AS (\n  SELECT LTRIM(RTRIM(value)) AS sku\n  FROM STRING_SPLIT(@skusCsv, ',')\n  WHERE LTRIM(RTRIM(value)) <> ''\n)\nSELECT\n  p.ItemCode, p.PriceList, l.ListName, l.Currency, p.Price\nFROM ITM1 p\nJOIN OPLN l ON l.ListNum = p.PriceList\nWHERE p.ItemCode IN (SELECT sku FROM skus)\n  AND (@priceList IS NULL OR p.PriceList = @priceList)\nORDER BY p.ItemCode, p.PriceList;",
  "params": {
    "skusCsv": "{skusCsv}",
    "priceList": {priceList}
  }
}

{
  "dbName": "{dbName}",
  "db": {
    "server": "{server}",
    "database": "{dbName}",
    "user": "{user}",
    "password": "<REDACTED>"
  },
  "query": "WITH skus AS (\n  SELECT LTRIM(RTRIM(value)) AS sku\n  FROM STRING_SPLIT(@skusCsv, ',')\n  WHERE LTRIM(RTRIM(value)) <> ''\n)\nSELECT\n  w.ItemCode, w.WhsCode, h.WhsName,\n  w.OnHand, w.IsCommited, w.OnOrder\nFROM OITW w\nJOIN OWHS h ON h.WhsCode = w.WhsCode\nWHERE w.ItemCode IN (SELECT sku FROM skus)\n  AND (@whsCode IS NULL OR w.WhsCode = @whsCode)\nORDER BY w.ItemCode, w.WhsCode;",
  "params": {
    "skusCsv": "{skusCsv}",
    "whsCode": "{whsCode}"
  }
}

{
  "dbName": "{dbName}",
  "db": {
    "server": "{server}",
    "database": "{dbName}",
    "user": "{user}",
    "password": "<REDACTED>"
  },
  "query": "WITH doc AS (\n  SELECT TOP (1) *\n  FROM ORDR\n  WHERE (DocEntry = @docEntry) OR (DocNum = @docNum)\n)\nSELECT\n  doc.*,\n  l.LineNum, l.ItemCode, l.Dscription, l.Quantity, l.OpenQty,\n  l.Price, l.DiscPrcnt, l.LineTotal,\n  l.WhsCode, l.ShipDate\nFROM doc\nLEFT JOIN RDR1 l ON l.DocEntry = doc.DocEntry\nORDER BY l.LineNum ASC;",
  "params": {
    "docEntry": {docEntry},
    "docNum": {docNum}
  }
}

{
  "dbName": "{dbName}",
  "db": {
    "server": "{server}",
    "database": "{dbName}",
    "user": "{user}",
    "password": "<REDACTED>"
  },
  "query": "WITH doc AS (\n  SELECT TOP (1) *\n  FROM OINV\n  WHERE (DocEntry = @docEntry) OR (DocNum = @docNum)\n)\nSELECT\n  doc.*,\n  l.LineNum, l.ItemCode, l.Dscription, l.Quantity,\n  l.Price, l.DiscPrcnt, l.LineTotal,\n  l.WhsCode\nFROM doc\nLEFT JOIN INV1 l ON l.DocEntry = doc.DocEntry\nORDER BY l.LineNum ASC;",
  "params": {
    "docEntry": {docEntry},
    "docNum": {docNum}
  }
}

{
  "dbName": "{dbName}",
  "db": {
    "server": "{server}",
    "database": "{dbName}",
    "user": "{user}",
    "password": "<REDACTED>"
  },
  "query": "SELECT\n  l.Quantity, l.Price, l.DiscPrcnt, l.LineTotal,\n  h.DocNum, h.DocDate, h.DocDueDate, h.DocStatus, h.CANCELED\nFROM OINV h\nJOIN INV1 l ON l.DocEntry = h.DocEntry\nWHERE\n  h.CardCode = @cardCode\n  AND l.ItemCode = @sku\n  AND h.CANCELED = 'N'\n  AND h.DocDate >= DATEADD(MONTH, -6, CAST(GETDATE() AS date))\nORDER BY h.DocDate DESC, h.DocEntry DESC;",
  "params": {
    "cardCode": "{cardCode}",
    "sku": "{sku}"
  }
}

{
  "dbName": "{dbName}",
  "db": {
    "server": "{server}",
    "database": "{dbName}",
    "user": "{user}",
    "password": "<REDACTED>"
  },
  "query": "SELECT\n  h.DocNum, h.DocDate, h.DocDueDate, h.CardCode, h.CardName,\n  l.ItemCode, l.Dscription, l.WhsCode, l.OpenQty, l.Quantity\nFROM OPOR h\nJOIN POR1 l ON l.DocEntry = h.DocEntry\nWHERE\n  h.CANCELED = 'N'\n  AND h.DocStatus = 'O'\n  AND l.ItemCode = @sku\n  AND l.OpenQty > 0\nORDER BY h.DocDueDate DESC, h.DocEntry DESC, l.LineNum ASC;",
  "params": {
    "sku": "{sku}"
  }
}

